    48→}
    49→
    50→// discordRiskColor returns a Discord embed color based on risk level.
    51→func discordRiskColor(level string) int {
    52→	switch strings.ToUpper(strings.TrimSpace(level)) {
    53→	case "CRITICAL":
    54→		return 0x111113 // near-black
    55→	case "HIGH":
    56→		return 0xDC2626 // red
    57→	case "MEDIUM":
    58→		return 0xD97706 // amber
    59→	case "LOW":
    60→		return 0x16A34A // green
    61→	default:
    62→		return 0x5865F2 // Discord blurple
    63→	}
    64→}
    65→
    66→// buildSemanticEmbed builds a rich Discord embed from a SemanticReport.
    67→func buildSemanticEmbed(title string, version string, report *models.SemanticReport, msg Notification) discordEmbed {
    68→	var descParts []string
    69→
    70→	if report.Subject != "" {
    71→		descParts = append(descParts, fmt.Sprintf("**%s**", report.Subject))
    72→	}
    73→
    74→	if report.RiskReason != "" {
    75→		descParts = append(descParts, fmt.Sprintf(">>> %s", report.RiskReason))
    76→	}
    77→
    78→	if len(report.StatusChecks) > 0 {
    79→		var checks []string
    80→		for _, check := range report.StatusChecks {
    81→			checks = append(checks, fmt.Sprintf("✅ %s", check))
    82→		}
    83→		descParts = append(descParts, strings.Join(checks, "\n"))
    84→	}
    85→
    86→	summary := report.ChangelogSummary
    87→	if summary == "" {
    88→		summary = report.Summary
    89→	}
    90→	if summary != "" {
    91→		descParts = append(descParts, fmt.Sprintf("**Changelog**\n%s", summary))
    92→	}
    93→
    94→	if len(report.DownloadCommands) > 0 {
    95→		descParts = append(descParts, fmt.Sprintf("**Download Commands**\n```\n%s\n```", strings.Join(report.DownloadCommands, "\n")))
    96→	}
    97→
    98→	if len(report.DownloadLinks) > 0 {
    99→		var links []string
   100→		for _, link := range report.DownloadLinks {
   101→			links = append(links, fmt.Sprintf("• %s", link))
   102→		}
   103→		descParts = append(descParts, fmt.Sprintf("**Download Links**\n%s", strings.Join(links, "\n")))
   104→	}
   105→
   106→	// Add links section
   107→	var linkParts []string
   108→	if msg.SourceURL != "" {
   109→		linkParts = append(linkParts, fmt.Sprintf("[View on %s](%s)", ProviderLabel(msg.Provider), msg.SourceURL))
   110→	}
   111→	if msg.ReleaseURL != "" {
   112→		linkParts = append(linkParts, fmt.Sprintf("[View in Changelogue](%s)", msg.ReleaseURL))
   113→	}
   114→	if len(linkParts) > 0 {
   115→		descParts = append(descParts, strings.Join(linkParts, "  •  "))
   116→	}
   117→
   118→	description := strings.Join(descParts, "\n\n")
   119→	if len(description) > discordEmbedDescriptionLimit {
   120→		description = description[:discordEmbedDescriptionLimit-3] + "..."
   121→	}
   122→
   123→	fields := []discordEmbedField{
   124→		{Name: "Risk Level", Value: fmt.Sprintf("%s %s", riskEmoji(report.RiskLevel), report.RiskLevel), Inline: true},
   125→		{Name: "Urgency", Value: report.Urgency, Inline: true},
   126→	}
   127→	if report.Availability != "" {
   128→		fields = append(fields, discordEmbedField{Name: "Availability", Value: report.Availability, Inline: true})
   129→	}
   130→	if report.Adoption != "" {
   131→		fields = append(fields, discordEmbedField{Name: "Adoption", Value: report.Adoption, Inline: false})
   132→	}
   133→
   134→	// Footer with source info
   135→	var footerText string
   136→	if msg.Provider != "" && msg.Repository != "" {
   137→		footerText = fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository)
   138→	}
   139→
   140→	embed := discordEmbed{
   141→		Title:       title,
   142→		Description: description,
   143→		Color:       discordRiskColor(report.RiskLevel),
   144→		Fields:      fields,
   145→	}
   146→	if footerText != "" {
   147→		embed.Footer = &discordEmbedFooter{Text: footerText}
   148→	}
   149→	return embed
   150→}
   151→
   152→func (s *DiscordSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   153→	var cfg discordConfig
   154→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   155→		return fmt.Errorf("parse discord config: %w", err)
   156→	}
   157→
   158→	var embed discordEmbed
   159→	var report models.SemanticReport
   160→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   161→		embed = buildSemanticEmbed(msg.Title, msg.Version, &report, msg)
   162→	} else {
   163→		// Fallback: extract known fields from raw data for a readable message.
   164→		var descParts []string
   165→		if fields, ok := parseRawBody(msg.Body); ok {
   166→			if fields.Changelog != "" {
   167→				descParts = append(descParts, fields.Changelog)
   168→			}
   169→		} else {
   170→			descParts = append(descParts, msg.Body)
   171→		}
   172→
   173→		// Add links
   174→		var linkParts []string
   175→		if msg.SourceURL != "" {
   176→			linkParts = append(linkParts, fmt.Sprintf("[View on %s](%s)", ProviderLabel(msg.Provider), msg.SourceURL))
   177→		}
   178→		if msg.ReleaseURL != "" {
   179→			linkParts = append(linkParts, fmt.Sprintf("[View in Changelogue](%s)", msg.ReleaseURL))
   180→		}
   181→		if len(linkParts) > 0 {
   182→			descParts = append(descParts, strings.Join(linkParts, "  •  "))
   183→		}
   184→
   185→		description := strings.Join(descParts, "\n\n")
   186→		if len(description) > discordEmbedDescriptionLimit {
   187→			description = description[:discordEmbedDescriptionLimit-3] + "..."
   188→		}
   189→
   190→		embed = discordEmbed{
   191→			Title:       msg.Title,
   192→			Description: description,
   193→			Color:       0x5865F2,
   194→			Fields: []discordEmbedField{
   195→				{Name: "Version", Value: msg.Version, Inline: true},
   196→			},
   197→		}
   198→		if msg.Provider != "" && msg.Repository != "" {
   199→			embed.Footer = &discordEmbedFooter{Text: fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository)}
   200→		}
   201→	}
   202→
   203→	payload := discordPayload{Embeds: []discordEmbed{embed}}
   204→
   205→	body, err := json.Marshal(payload)
   206→	if err != nil {
   207→		return fmt.Errorf("marshal discord payload: %w", err)
   208→	}
   209→
   210→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   211→	if err != nil {
   212→		return fmt.Errorf("create request: %w", err)
   213→	}
   214→	req.Header.Set("Content-Type", "application/json")
   215→
   216→	client := s.Client
   217→	if client == nil {
   218→		client = http.DefaultClient
   219→	}
   220→
   221→	resp, err := client.Do(req)
   222→	if err != nil {
   223→		return fmt.Errorf("send discord notification: %w", err)
   224→	}
   225→	defer resp.Body.Close()
   226→
   227→	if resp.StatusCode >= 400 {
   228→		return fmt.Errorf("discord returned status %d", resp.StatusCode)
   229→	}
   230→	return nil
   231→}
