    39→
    40→// urgencyEmoji returns an emoji indicator for the given urgency level.
    41→func urgencyEmoji(level string) string {
    42→	switch strings.ToUpper(strings.TrimSpace(level)) {
    43→	case "LOW":
    44→		return "🟢"
    45→	case "MEDIUM":
    46→		return "🟡"
    47→	case "HIGH":
    48→		return "🔴"
    49→	case "CRITICAL":
    50→		return "⚫"
    51→	default:
    52→		return "⚪"
    53→	}
    54→}
    55→
    56→// buildSemanticBlocks builds compact Slack Block Kit blocks from a SemanticReport.
    57→// For Critical/High urgency, includes the urgency reason. For Low/Medium, omits it.
    58→func buildSemanticBlocks(title string, report *models.SemanticReport, msg Notification) []slackBlock {
    59→	// Resolve urgency from new field or backward-compat risk_level
    60→	urgency := report.Urgency
    61→	if urgency == "" {
    62→		urgency = report.RiskLevel
    63→	}
    64→	urgencyReason := report.UrgencyReason
    65→	if urgencyReason == "" {
    66→		urgencyReason = report.RiskReason
    67→	}
    68→
    69→	// Header: "ProjectName vX.Y.Z — 🟢 Low Urgency"
    70→	headerText := title
    71→	if urgency != "" {
    72→		headerText = fmt.Sprintf("%s — %s %s Urgency", title, urgencyEmoji(urgency), urgency)
    73→	}
    74→	// Slack header max is 150 chars
    75→	if len(headerText) > 150 {
    76→		headerText = headerText[:147] + "..."
    77→	}
    78→
    79→	blocks := []slackBlock{
    80→		{Type: "header", Text: &slackText{Type: "plain_text", Text: headerText}},
    81→	}
    82→
    83→	// Urgency reason (only for Critical/High)
    84→	upperUrgency := strings.ToUpper(strings.TrimSpace(urgency))
    85→	if (upperUrgency == "CRITICAL" || upperUrgency == "HIGH") && urgencyReason != "" {
    86→		blocks = append(blocks, slackBlock{
    87→			Type: "section",
    88→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("⚠️ %s", urgencyReason)},
    89→		})
    90→	}
    91→
    92→	// Changelog summary
    93→	summary := report.ChangelogSummary
    94→	if summary == "" {
    95→		summary = report.Summary
    96→	}
    97→	if summary != "" {
    98→		blocks = append(blocks, slackBlock{
    99→			Type: "section",
   100→			Text: &slackText{Type: "mrkdwn", Text: summary},
   101→		})
   102→	}
   103→
   104→	// First download command only
   105→	if len(report.DownloadCommands) > 0 {
   106→		blocks = append(blocks, slackBlock{
   107→			Type: "section",
   108→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("`%s`", report.DownloadCommands[0])},
   109→		})
   110→	}
   111→
   112→	// Footer context with source info and links
   113→	var footerParts []string
   114→	if msg.Provider != "" && msg.Repository != "" {
   115→		footerParts = append(footerParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
   116→	}
   117→	if msg.SourceURL != "" {
   118→		footerParts = append(footerParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
   119→	}
   120→	if msg.ReleaseURL != "" {
   121→		footerParts = append(footerParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
   122→	}
   123→	if len(footerParts) > 0 {
   124→		blocks = append(blocks, slackBlock{
   125→			Type: "context",
   126→			Elements: []slackText{
   127→				{Type: "mrkdwn", Text: strings.Join(footerParts, "  |  ")},
   128→			},
   129→		})
   130→	}
   131→
   132→	return blocks
   133→}
