   135→func (s *SlackSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   136→	var cfg slackConfig
   137→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   138→		return fmt.Errorf("parse slack config: %w", err)
   139→	}
   140→
   141→	// Try to parse body as a SemanticReport for rich formatting.
   142→	var blocks []slackBlock
   143→	var report models.SemanticReport
   144→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   145→		blocks = buildSemanticBlocks(msg.Title, &report, msg)
   146→	} else {
   147→		// Fallback: extract known fields from raw data for a readable message.
   148→		blocks = []slackBlock{
   149→			{Type: "header", Text: &slackText{Type: "plain_text", Text: msg.Title}},
   150→		}
   151→		if fields, ok := parseRawBody(msg.Body); ok {
   152→			if fields.Changelog != "" {
   153→				blocks = append(blocks, slackBlock{
   154→					Type: "section",
   155→					Text: &slackText{Type: "mrkdwn", Text: fields.Changelog},
   156→				})
   157→			}
   158→		} else {
   159→			blocks = append(blocks, slackBlock{
   160→				Type: "section",
   161→				Text: &slackText{Type: "mrkdwn", Text: msg.Body},
   162→			})
   163→		}
   164→
   165→		// Add source info and links
   166→		var linkParts []string
   167→		if msg.Provider != "" && msg.Repository != "" {
   168→			linkParts = append(linkParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
   169→		}
   170→		if msg.SourceURL != "" {
   171→			linkParts = append(linkParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
   172→		}
   173→		if msg.ReleaseURL != "" {
   174→			linkParts = append(linkParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
   175→		}
   176→		if len(linkParts) > 0 {
   177→			blocks = append(blocks, slackBlock{
   178→				Type: "context",
   179→				Elements: []slackText{
   180→					{Type: "mrkdwn", Text: strings.Join(linkParts, "  |  ")},
   181→				},
   182→			})
   183→		}
   184→	}
   185→
   186→	payload := slackPayload{Blocks: blocks}
   187→
   188→	body, err := json.Marshal(payload)
   189→	if err != nil {
   190→		return fmt.Errorf("marshal slack payload: %w", err)
   191→	}
   192→
   193→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   194→	if err != nil {
   195→		return fmt.Errorf("create request: %w", err)
   196→	}
   197→	req.Header.Set("Content-Type", "application/json")
   198→
   199→	client := s.Client
   200→	if client == nil {
   201→		client = http.DefaultClient
   202→	}
   203→
   204→	resp, err := client.Do(req)
   205→	if err != nil {
   206→		return fmt.Errorf("send slack notification: %w", err)
   207→	}
   208→	defer resp.Body.Close()
   209→
   210→	if resp.StatusCode >= 400 {
   211→		return fmt.Errorf("slack returned status %d", resp.StatusCode)
   212→	}
   213→	return nil
   214→}
