		t.Fatalf("compact format should not have embed fields, got %d", len(embed.Fields))
	}

	// Color should be CRITICAL near-black
	if embed.Color != 0x111113 {
		t.Fatalf("expected critical color 0x111113, got 0x%06X", embed.Color)
	}
}
