   139→func (s *DiscordSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   140→	var cfg discordConfig
   141→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   142→		return fmt.Errorf("parse discord config: %w", err)
   143→	}
   144→
   145→	var embed discordEmbed
   146→	var report models.SemanticReport
   147→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   148→		embed = buildSemanticEmbed(msg.Title, msg.Version, &report, msg)
   149→	} else {
   150→		// Fallback: extract known fields from raw data for a readable message.
   151→		var descParts []string
   152→		if fields, ok := parseRawBody(msg.Body); ok {
   153→			if fields.Changelog != "" {
   154→				descParts = append(descParts, fields.Changelog)
   155→			}
   156→		} else {
   157→			descParts = append(descParts, msg.Body)
   158→		}
   159→
   160→		// Add links
   161→		var linkParts []string
   162→		if msg.SourceURL != "" {
   163→			linkParts = append(linkParts, fmt.Sprintf("[View on %s](%s)", ProviderLabel(msg.Provider), msg.SourceURL))
   164→		}
   165→		if msg.ReleaseURL != "" {
   166→			linkParts = append(linkParts, fmt.Sprintf("[View in Changelogue](%s)", msg.ReleaseURL))
   167→		}
   168→		if len(linkParts) > 0 {
   169→			descParts = append(descParts, strings.Join(linkParts, "  •  "))
   170→		}
   171→
   172→		description := strings.Join(descParts, "\n\n")
   173→		if len(description) > discordEmbedDescriptionLimit {
   174→			description = description[:discordEmbedDescriptionLimit-3] + "..."
   175→		}
   176→
   177→		embed = discordEmbed{
   178→			Title:       msg.Title,
   179→			Description: description,
   180→			Color:       0x5865F2,
   181→			Fields: []discordEmbedField{
   182→				{Name: "Version", Value: msg.Version, Inline: true},
   183→			},
   184→		}
   185→		if msg.Provider != "" && msg.Repository != "" {
   186→			embed.Footer = &discordEmbedFooter{Text: fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository)}
   187→		}
   188→	}
   189→
   190→	payload := discordPayload{Embeds: []discordEmbed{embed}}
   191→
   192→	body, err := json.Marshal(payload)
   193→	if err != nil {
   194→		return fmt.Errorf("marshal discord payload: %w", err)
   195→	}
   196→
   197→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   198→	if err != nil {
   199→		return fmt.Errorf("create request: %w", err)
   200→	}
   201→	req.Header.Set("Content-Type", "application/json")
   202→
   203→	client := s.Client
   204→	if client == nil {
   205→		client = http.DefaultClient
   206→	}
   207→
   208→	resp, err := client.Do(req)
   209→	if err != nil {
   210→		return fmt.Errorf("send discord notification: %w", err)
