     1→package routing
     2→
     3→import (
     4→	"context"
     5→	"encoding/json"
     6→	"fmt"
     7→	"log/slog"
     8→	"net/http"
     9→	"regexp"
    10→	"strings"
    11→	"time"
    12→
    13→	"github.com/riverqueue/river"
    14→	"github.com/sentioxyz/changelogue/internal/models"
    15→	"github.com/sentioxyz/changelogue/internal/queue"
    16→)
    17→
    18→// NotifyStore is the data access interface required by the notification worker.
    19→type NotifyStore interface {
    20→	GetRelease(ctx context.Context, id string) (*models.Release, error)
    21→	GetSource(ctx context.Context, id string) (*models.Source, error)
    22→	ListSourceSubscriptions(ctx context.Context, sourceID string) ([]models.Subscription, error)
    23→	GetChannel(ctx context.Context, id string) (*models.NotificationChannel, error)
    24→	GetProject(ctx context.Context, id string) (*models.Project, error)
    25→	GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error)
    26→	EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error
    27→}
    28→
    29→// NotifyWorker is a River worker that processes NotifyJobArgs.
    30→// It looks up the release, finds all source-level subscriptions, resolves
    31→// the notification channel for each, and dispatches via the appropriate sender.
    32→// After sending notifications, it checks the project's agent rules and
    33→// auto-triggers an agent run if the version criteria are met.
    34→type NotifyWorker struct {
    35→	river.WorkerDefaults[queue.NotifyJobArgs]
    36→	store     NotifyStore
    37→	senders   map[string]Sender
    38→	publicURL string // base URL for internal Changelogue links (e.g. "https://changelogue.example.com")
    39→}
    40→
    41→// NewSenders returns the default sender map for webhook, Slack, and Discord.
    42→func NewSenders() map[string]Sender {
    43→	return map[string]Sender{
    44→		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    45→		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    46→		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    47→	}
    48→}
    49→
    50→// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    51→func NewNotifyWorker(store NotifyStore, publicURL string) *NotifyWorker {
    52→	return &NotifyWorker{
    53→		store:     store,
    54→		senders:   NewSenders(),
    55→		publicURL: strings.TrimRight(publicURL, "/"),
    56→	}
    57→}
    58→
    59→// VersionPassesFilter returns true if the version string passes the source's
    60→// include/exclude regex filters. When both are nil the version always passes.
    61→func VersionPassesFilter(version string, include, exclude *string) bool {
    62→	if include != nil && *include != "" {
    63→		matched, err := regexp.MatchString(*include, version)
    64→		if err != nil || !matched {
    65→			return false
    66→		}
    67→	}
    68→	if exclude != nil && *exclude != "" {
    69→		matched, err := regexp.MatchString(*exclude, version)
    70→		if err != nil || matched {
    71→			return false
    72→		}
    73→	}
    74→	return true
    75→}
    76→
    77→// Work processes a notify job: fetches the release, resolves subscriptions,
    78→// sends notifications to all matching channels, and checks agent rules to
    79→// auto-trigger agent runs when version criteria are met.
    80→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    81→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    82→	if err != nil {
    83→		return fmt.Errorf("get release: %w", err)
    84→	}
    85→
    86→	// Check source version filters — skip entirely if filtered out.
    87→	source, err := w.store.GetSource(ctx, job.Args.SourceID)
    88→	if err != nil {
    89→		return fmt.Errorf("get source: %w", err)
    90→	}
    91→	if !VersionPassesFilter(release.Version, source.VersionFilterInclude, source.VersionFilterExclude) {
    92→		slog.Debug("release filtered by version filter", "version", release.Version, "source_id", job.Args.SourceID)
    93→		return nil
    94→	}
    95→
    96→	// Check exclude_prereleases — skip if source excludes prereleases and this is one.
    97→	if source.ExcludePrereleases {
    98→		var rawData map[string]interface{}
    99→		if err := json.Unmarshal(release.RawData, &rawData); err == nil {
   100→			if prerelease, _ := rawData["prerelease"].(string); prerelease == "true" {
   101→				slog.Debug("release filtered by exclude_prereleases", "version", release.Version, "source_id", job.Args.SourceID)
   102→				return nil
   103→			}
   104→		}
   105→	}
   106→
   107→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
   108→	if err != nil {
   109→		return fmt.Errorf("list subscriptions: %w", err)
   110→	}
   111→
   112→	for _, sub := range subs {
   113→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
   114→		if err != nil {
   115→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
   116→			continue
   117→		}
   118→
   119→		sender, ok := w.senders[ch.Type]
   120→		if !ok {
   121→			slog.Warn("unknown channel type", "type", ch.Type)
   122→			continue
   123→		}
   124→
   125→		// Build title with project name if available.
   126→		title := fmt.Sprintf("New release: %s", release.Version)
   127→		if release.ProjectName != "" {
   128→			title = fmt.Sprintf("%s — New release: %s", release.ProjectName, release.Version)
   129→		}
   130→
   131→		msg := Notification{
   132→			Title:       title,
   133→			Body:        string(release.RawData),
   134→			Version:     release.Version,
   135→			ProjectName: release.ProjectName,
   136→			Provider:    release.Provider,
   137→			Repository:  release.Repository,
   138→			SourceURL:   ProviderURL(release.Provider, release.Repository, release.Version),
   139→		}
   140→		if w.publicURL != "" {
   141→			msg.ReleaseURL = fmt.Sprintf("%s/releases/%s", w.publicURL, release.ID)
   142→		}
   143→
   144→		if err := sender.Send(ctx, ch, msg); err != nil {
   145→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
   146→		}
