// changelogMaxLines is the maximum number of lines to show in a source-level
// release notification before truncating with a "Show more" link.
const changelogMaxLines = 5

// truncateChangelog truncates text to maxLines. Returns the truncated text
// and whether truncation occurred.
func truncateChangelog(text string, maxLines int) (string, bool) {
	lines := strings.Split(text, "\n")
	if len(lines) <= maxLines {
		return text, false
	}
	return strings.Join(lines[:maxLines], "\n"), true
}

